// app-alerts.js — page module extracted from app.js (buildless, classic script;
// all symbols remain global like the rest of the client JS).
// Generated by refactor extraction. Do not add a build step.

// ─── v3.2.0 (B1): Alerts inbox ──────────────────────────────────────────────

let _alertsCache = [];
let _alertsAckCommentEnabled = true;   // v4.1.0 (#56): prompt for ack comment

async function loadAlerts() {
  const statusEl = document.getElementById('alerts-filter-status');
  const status = (statusEl && statusEl.value) || 'open';
  try {
    const data = await api('GET', `/alerts?status=${encodeURIComponent(status)}&limit=500`);
    _alertsCache = (data && data.alerts) || [];
    window._alertsSummary = (data && data.summary) || null;   // v6.3.0 (wave 8): blast-radius counts
    // v4.1.0 (#56): whether to prompt for an optional comment on ack.
    _alertsAckCommentEnabled = !data || data.ack_comment_enabled !== false;
    _renderAlertsSummary(data && data.summary);
    renderAlerts();
    _focusPendingAlert();   // v6.3.0 (UX wave 3): #alerts/<id> deep link
  } catch (e) {
    toast('Failed to load alerts', 'error');
  }
}

// ── v6.3.0 (UX wave 3): per-alert deep links ─────────────────────────────────
// #alerts/<id> — the id is stashed in _pendingAlertDeepLink by the boot router
// / hashchange listener (app.js) before showPage rewrites the hash; consumed
// here once rows exist. If the alert isn't in the current status filter
// (e.g. already resolved), widen to "all" ONCE and retry.
function copyAlertLink(id) {
  const url = `${location.origin}${location.pathname}#alerts/${encodeURIComponent(String(id))}`;
  if (!navigator.clipboard) { toast('Clipboard unavailable', 'error'); return; }
  navigator.clipboard.writeText(url).then(
    () => toast('Alert link copied', 'success'),
    () => toast('Could not copy', 'error'));
}
function _focusPendingAlert() {
  const id = window._pendingAlertDeepLink;
  if (!id || !/^[A-Za-z0-9_-]{1,64}$/.test(String(id))) return;
  const row = document.querySelector(`#page-alerts .alerts-row[data-alert-id="${id}"]`);
  if (!row) {
    const st = document.getElementById('alerts-filter-status');
    if (st && st.value !== 'all' && !window._alertDeepLinkWidened) {
      window._alertDeepLinkWidened = true;
      st.value = 'all';
      loadAlerts();
      return;
    }
    window._pendingAlertDeepLink = null;
    window._alertDeepLinkWidened = false;
    toast('Alert not found — it may have been purged', 'info');
    return;
  }
  window._pendingAlertDeepLink = null;
  window._alertDeepLinkWidened = false;
  row.scrollIntoView({ block: 'center' });
  const rows = _kbAlertRows();
  _kbAlertIdx = rows.indexOf(row);
  _kbAlertPaint(rows);
}

// ── v4.9.0 ResolutionMatters #4: alert-resolution timeline (MTTR) ────────────
async function loadAlertMttr() {
  const daysEl = document.getElementById('mttr-days');
  const days = (daysEl && daysEl.value) || '30';
  const summary = document.getElementById('mttr-summary');
  const hostsBox = document.getElementById('mttr-hosts');
  const tb = document.getElementById('mttr-tbody');
  if (summary) summary.textContent = 'Loading…';
  const data = await api('GET', `/alerts/resolution-stats?days=${encodeURIComponent(days)}`);
  if (!data) { if (summary) summary.textContent = 'Failed to load'; return; }
  if (summary) summary.textContent =
    `${data.resolved_count} resolved · MTTR mean ${_fmtDuration(data.mttr_mean)} · median ${_fmtDuration(data.mttr_median)} · MTTA ${_fmtDuration(data.mtta_mean)}`;
  if (hostsBox) {
    const hosts = (data.hosts || []).slice(0, 12);
    hostsBox.innerHTML = hosts.length
      ? '<div class="hint mb-8">Per host:</div>' + hosts.map(h =>
          `<span class="group-badge" title="${escAttr(h.host)} · ${h.count} resolved · mean MTTR ${_fmtDuration(h.mttr_mean)}">${escHtml(h.host)} ${h.count} · ${escHtml(_fmtDuration(h.mttr_mean))}</span>`).join(' ')
      : '';
  }
  if (!tb) return;
  const sevCls = { critical: 'c-red', high: 'c-red', medium: 'c-amber', low: 'c-muted', info: 'c-muted' };
  const howBadge = { auto: 'c-green', manual: 'c-accent', muted: 'c-muted', unknown: 'c-muted' };
  const rows = data.timeline || [];
  tb.innerHTML = rows.length ? rows.map(t => {
    const when = t.resolved_at ? new Date(t.resolved_at * 1000).toLocaleString() : '—';
    const by = t.how === 'manual' ? (t.resolved_by || t.acknowledged_by || '—') : (t.how === 'auto' ? 'recover event' : (t.resolved_by || '—'));
    const note = t.note ? `<div class="hint">${escHtml(t.note)}</div>` : '';
    return `<tr><td class="meta-sm-nm">${escHtml(when)}</td>`
      + `<td class="${sevCls[t.severity] || 'c-muted'}">${escHtml(t.severity || '')}</td>`
      + `<td>${escHtml(t.title || t.event || '')}${note}</td>`
      + `<td>${escHtml(t.host || '')}</td>`
      + `<td class="meta-sm-nm">${t.mttr != null ? escHtml(_fmtDuration(t.mttr)) : '—'}</td>`
      + `<td class="${howBadge[t.how] || 'c-muted'}">${escHtml(t.how || '')}</td>`
      + `<td>${escHtml(by)}</td></tr>`;
  }).join('') : '<tr><td colspan="7" class="hint">No resolved alerts in this window.</td></tr>';
}

function _renderAlertsSummary(summary) {
  const el = document.getElementById('alerts-summary');
  if (!el) return;
  if (!summary) { el.innerHTML = ''; return; }
  const bs = summary.by_severity || {};
  el.innerHTML =
    `<span class="alerts-summary-pill">Open: <strong>${summary.open || 0}</strong></span>` +
    `<span class="alerts-summary-pill">Acknowledged: <strong>${summary.acknowledged || 0}</strong></span>` +
    `<span class="alerts-summary-pill">Resolved: <strong>${summary.resolved || 0}</strong></span>` +
    (bs.critical ? `<span class="alerts-summary-pill sev-pill sev-critical">Critical: ${bs.critical}</span>` : '') +
    (bs.high ? `<span class="alerts-summary-pill sev-pill sev-high">High: ${bs.high}</span>` : '') +
    _alertsHeatStrip();
}

// v6.3.0 (UX wave 10): per-day volume strip over the LOADED alerts (a
// GitHub-graph miniature) — weekly patterns and "what changed Tuesday" at a
// glance. Intensity via inline opacity steps on the accent (CSS class based,
// no style attributes — CSP).
function _alertsHeatStrip() {
  const byDay = new Map();
  for (const a of (_alertsCache || [])) {
    if (!a.ts) continue;
    const d = new Date(a.ts * 1000);
    const key = `${d.getFullYear()}-${d.getMonth() + 1}-${d.getDate()}`;
    byDay.set(key, (byDay.get(key) || 0) + 1);
  }
  if (byDay.size < 2) return '';
  const cells = [];
  const now = new Date();
  let max = 1;
  for (const v of byDay.values()) max = Math.max(max, v);
  for (let i = 41; i >= 0; i--) {
    const d = new Date(now.getFullYear(), now.getMonth(), now.getDate() - i);
    const key = `${d.getFullYear()}-${d.getMonth() + 1}-${d.getDate()}`;
    const n = byDay.get(key) || 0;
    const lvl = n === 0 ? 0 : Math.min(4, 1 + Math.floor((n / max) * 3));
    cells.push(`<span class="alert-heat-cell heat-l${lvl}" title="${escAttr(d.toLocaleDateString())}: ${n} alert${n === 1 ? '' : 's'}"></span>`);
  }
  return `<span class="alert-heat-row" title="Alert volume per day (last 6 weeks, loaded alerts)">${cells.join('')}</span>`;
}

const _ALERT_SEV_RANK = { critical: 0, high: 1, medium: 2, low: 3, info: 4 };
const _ALERT_SEV_NAME = ['critical', 'high', 'medium', 'low'];
// v4.1.0: per-host grouping state. Default grouped; collapsed set persists
// across re-renders within the session.
const _alertGroupsCollapsed = new Set();
function _alertHostKey(a) {
  return a.device_id || (a.device_name ? 'name:' + a.device_name : '__fleet__');
}
// One alert <tr>. role: '' | 'root' | 'symptom' (controls the badge + indent).
function _alertRowHtml(a, role) {
  const isResolved = !!a.resolved_at;
  const ackBy = a.acknowledged_by ? _escapeHtml(a.acknowledged_by) : '—';
  const sev = (a.severity || 'medium');
  const sevPill = `<span class="sev-pill sev-${escAttr(sev)}">${escHtml(sev)}</span>`;
  const dev = a.device_name || a.device_id || '—';
  const ts = _formatTs(a.ts);
  let actions = '';
  if (!isResolved) {
    actions += `<button class="btn-icon btn-xs" data-action="aiInvestigateAlert" data-arg="${a.id}" title="AI: investigate this alert and suggest fixes">${_icon('sparkles',14)} Investigate</button> `;
    // v6.3.1: agentic triage — the model gathers evidence via read-only tools
    // (journal, log search, sibling alerts, latest log sweep) and stores a
    // verdict + evidence trail on the alert.
    actions += `<button class="btn-icon btn-xs" data-action="aiTriageAlert" data-arg="${a.id}" title="AI triage: agentic investigation — the model gathers evidence through read-only tools and stores a verdict on this alert">${_icon('search',14)} Triage</button> `;
    // v5.8.0 (B1.2): one-click remediation when the server tagged a playbook
    // for this alert's event (mitigation_kind set only when a device + playbook
    // apply). Opens the same diagnostic→AI→fix runner as the dashboard feed.
    if (a.mitigation_kind && a.device_id) {
      actions += `<button class="btn-icon btn-xs" data-action="mitigateAlert" data-arg="${a.id}" title="Fix: run the guided remediation playbook for this alert">${_icon('wrench',14)} Fix</button> `;
    }
    actions += `<button class="btn-icon btn-xs" data-action="muteAlert" data-arg="${a.id}" title="Mute: silence this exact alert (${_escapeHtml(a.event || '')}) from this host. Lift it under Monitoring → Tuning.">${_icon('bellOff',14)} Mute</button> `;
    actions += `<button class="btn-icon btn-xs c-success" data-action="resolveAlert" data-arg="${a.id}">Resolve</button> `;
    actions += `<button class="btn-icon btn-xs" data-action="copyAlertLink" data-arg="${a.id}" title="Copy a link to this alert" aria-label="Copy a link to this alert">${_icon('link',12)}</button>`;
    if (window._ticketsOn && !a.rp_ticket) {
      actions += ` <button class="btn-icon btn-xs" data-action="createTicketFromAlert" data-arg="${a.id}" title="Open an incident ticket from this alert">Ticket</button>`;
    }
  } else {
    const byWho = a.resolved_by === 'auto' ? 'auto' : _escapeHtml(a.resolved_by || '');
    actions = `<span class="c-muted">resolved by ${byWho}</span> `
      + `<button class="btn-icon btn-xs" data-action="copyAlertLink" data-arg="${a.id}" title="Copy a link to this alert" aria-label="Copy a link to this alert">${_icon('link',12)}</button>`;
  }
  const cb = isResolved ? '' :
    `<input type="checkbox" class="alerts-row-cb" data-id="${a.id}" data-action="updateBulkResolveBtn">`;
  const badge = role === 'root'
    ? ' <span class="alert-rc-badge rc-root">root cause</span>'
    : role === 'symptom' ? ' <span class="alert-rc-badge rc-symptom">symptom</span>' : '';
  const titleCls = role === 'symptom' ? ' class="alert-symptom-cell"' : '';
  // v5.0.0: ITSM ticket opened on ack — link straight to it.
  const ticketLink = a.ticket_ref
    ? (a.ticket_url
        ? ` <a href="${_safeHttpHref(a.ticket_url)}" target="_blank" rel="noopener" class="patch-badge ok fs-10" title="Open the linked ticket">Ticket ${_escapeHtml(a.ticket_ref)} <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="11" height="11" stroke-linecap="round" stroke-linejoin="round"><line x1="7" y1="17" x2="17" y2="7"/><polyline points="7 7 17 7 17 17"/></svg></a>`
        : ` <span class="patch-badge ok fs-10" title="Linked ticket">Ticket ${_escapeHtml(a.ticket_ref)}</span>`)
    : '';
  // W1-23: linked KB runbook for this event, if an admin mapped one.
  const kbLink = (a.kb_link && a.kb_link.id)
    ? ` <a href="#" data-action="openKbFromAlert" data-arg="${_escapeHtml(a.kb_link.id)}" data-prevent-default class="patch-badge fs-10" title="Open the runbook for this alert">${_icon('bookOpen',11)} ${_escapeHtml(a.kb_link.title || 'Runbook')}</a>`
    : '';
  return `<tr class="alerts-row${isResolved ? ' resolved' : ''}${role ? ' alert-' + role : ''}${(sev === 'critical' && !isResolved) ? ' alert-crit' : ''}" data-alert-id="${_escapeHtml(String(a.id))}">
    <td>${cb}</td>
    <td>${sevPill}</td>
    <td class="nowrap">${ts}</td>
    <td${titleCls}>${_escapeHtml(a.title || a.event || '')}${badge}${ticketLink}${kbLink}${a.ai_triage ? ` <button class="patch-badge fs-10" data-action="showAlertTriage" data-arg="${a.id}" title="AI triage verdict stored — click to view">${_icon('sparkles',11)} AI verdict</button>` : ''}${a.rp_ticket ? ` <span class="patch-badge ok fs-10" title="Built-in ticket">${_escapeHtml(_tkNo(a.rp_ticket))}</span>` : ''}${a.alertid ? `<div class="hint">${_escapeHtml(_rpNo(a.alertid))}</div>` : ''}</td>
    <td>${a.device_id ? `<span data-dev-hover="${_escapeHtml(a.device_id)}">${_escapeHtml(dev)}</span>` : _escapeHtml(dev)}</td>
    <td>${ackBy}</td>
    <td class="nowrap">${actions}</td>
  </tr>`;
}
function renderAlerts() {
  const filterEl = document.getElementById('alerts-filter-text');
  const q = ((filterEl && filterEl.value) || '').trim().toLowerCase();
  let rows = _alertsCache;
  if (q) {
    rows = rows.filter(a =>
      (a.title || '').toLowerCase().includes(q) ||
      (a.device_name || '').toLowerCase().includes(q) ||
      (a.event || '').toLowerCase().includes(q));
  }
  tableCtl.wireSortOnly('alerts-thead', 'alerts', renderAlerts);
  const tbody = document.getElementById('alerts-tbody');
  if (!tbody) return;
  if (!rows.length) {
    // v6.3.0 (UX wave 10): calm geometric all-clear mark instead of bare text.
    tbody.innerHTML = '<tr><td colspan="7" class="empty-state">'
      + '<svg class="rp-empty-art" aria-hidden="true" width="44" height="44" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round">'
      + '<circle cx="12" cy="12" r="10"/><circle cx="12" cy="12" r="6" opacity=".4"/><polyline points="9 12 11 14 15 10"/></svg>'
      + 'No alerts in this view.</td></tr>';
    _updateBulkResolveBtn();
    return;
  }
  const groupEl = document.getElementById('alerts-group-host');
  const grouped = groupEl ? groupEl.checked : true;
  if (grouped) { _renderAlertsGrouped(rows); }
  else { _renderAlertsFlat(rows); }
  _updateBulkResolveBtn();
}
function _renderAlertsFlat(rows) {
  // v3.2.1: sortable. Default = ts desc (newest first); operator can override.
  rows = tableCtl.sortRows('alerts', rows, (a) => ({
    severity:        _ALERT_SEV_RANK[a.severity] ?? 99,
    ts:              a.ts || 0,
    title:           (a.title || '').toLowerCase(),
    device_name:     (a.device_name || '').toLowerCase(),
    acknowledged_by: a.acknowledged_by || '',
  }));
  // v6.2.2: chunked — a busy fleet's flat view can hold thousands of alerts.
  tableCtl.renderChunked('alerts-tbody',
    rows.map(a => _alertRowHtml(a, '')), {colspan: 7});
}
function _renderAlertsGrouped(rows) {
  // Bucket by host, then order groups worst-severity → most-open → name.
  const groups = new Map();
  for (const a of rows) {
    const k = _alertHostKey(a);
    if (!groups.has(k)) groups.set(k, []);
    groups.get(k).push(a);
  }
  const arr = [...groups.entries()].map(([key, items]) => {
    const worst = Math.min(99, ...items.map(a => _ALERT_SEV_RANK[a.severity] ?? 99));
    const openCount = items.filter(a => !a.resolved_at).length;
    return {
      key, items,
      name: items[0].device_name || items[0].device_id || 'Fleet / no host',
      worst, openCount, hasRoot: items.some(a => a._root_cause),
    };
  });
  arr.sort((x, y) => x.worst - y.worst || y.openCount - x.openCount
    || x.name.localeCompare(y.name));
  const order = a => a._root_cause ? 0 : a._symptom_of ? 1 : 2;
  let html = '';
  for (const g of arr) {
    if (g.items.length === 1) { html += _alertRowHtml(g.items[0], ''); continue; }
    const items = g.items.slice().sort((a, b) =>
      order(a) - order(b)
      || (_ALERT_SEV_RANK[a.severity] ?? 9) - (_ALERT_SEV_RANK[b.severity] ?? 9)
      || (b.ts || 0) - (a.ts || 0));
    const collapsed = _alertGroupsCollapsed.has(g.key);
    const worstName = _ALERT_SEV_NAME[g.worst] || 'low';
    const caret = collapsed ? '<svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="12" height="12" stroke-linecap="round" stroke-linejoin="round"><polyline points="9 18 15 12 9 6"/></svg>' : '<svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="12" height="12" stroke-linecap="round" stroke-linejoin="round"><polyline points="6 9 12 15 18 9"/></svg>';
    const rootNote = g.hasRoot ? ' · host offline — symptoms folded' : '';
    let groupActions = '';
    if (g.openCount) {
      groupActions =
        `<button class="btn-icon btn-xs" data-action="ackGroup" data-arg="${escAttr(g.key)}">Ack all</button> ` +
        `<button class="btn-icon btn-xs c-success" data-action="resolveGroup" data-arg="${escAttr(g.key)}">Resolve all</button>`;
    }
    html += `<tr class="alerts-group-row">
      <td colspan="6"><button class="alerts-group-toggle" data-action="toggleAlertGroup" data-arg="${escAttr(g.key)}">${caret} <strong>${_escapeHtml(g.name)}</strong></button> <span class="sev-pill sev-${worstName}">${worstName}</span> <span class="hint">${g.openCount} open / ${g.items.length} total${rootNote}</span></td>
      <td class="nowrap">${groupActions}</td></tr>`;
    if (!collapsed) {
      for (const a of items) {
        html += _alertRowHtml(a, a._root_cause ? 'root' : a._symptom_of ? 'symptom' : '');
      }
    }
  }
  document.getElementById('alerts-tbody').innerHTML = html;
}
function toggleAlertGroup(key) {
  if (_alertGroupsCollapsed.has(key)) _alertGroupsCollapsed.delete(key);
  else _alertGroupsCollapsed.add(key);
  renderAlerts();
}
async function ackGroup(key) {
  const ids = (_alertsCache || []).filter(a =>
    _alertHostKey(a) === key && !a.resolved_at && !a.acknowledged_at).map(a => a.id);
  if (!ids.length) { toast('Nothing to acknowledge on this host', 'info'); return; }
  const body = { ids };
  if (_alertsAckCommentEnabled) {
    const note = await uiPrompt({message: `Add a comment to ${ids.length} acknowledgement(s) (optional):`, value: ''});
    if (note === null) return;
    if (note.trim()) body.note = note.trim();
  }
  const r = await api('POST', '/alerts/bulk-ack', body);
  if (r && r.ok) { toast(`Acknowledged ${r.acked}`, 'success'); loadAlerts(); refreshAlertsBadge(); }
  else toast((r && r.error) || 'Failed', 'error');
}
async function resolveGroup(key) {
  const ids = (_alertsCache || []).filter(a =>
    _alertHostKey(a) === key && !a.resolved_at).map(a => a.id);
  if (!ids.length) return;
  if (!await uiConfirm(`Resolve ${ids.length} alert(s) on this host?`)) return;
  const r = await api('POST', '/alerts/bulk-resolve', { ids });
  if (r && r.ok) { toast(`Resolved ${r.resolved}`, 'success'); loadAlerts(); refreshAlertsBadge(); }
  else toast((r && r.error) || 'Failed', 'error');
}

// v5.6.0: mute = silence this exact (host, event) — replaces the per-row Ack
// button. Clears any currently-open matching alerts.
//
// v6.1.2: the mute can now be TIMED. A permanent mute you forget to lift is a
// signal you have silently stopped monitoring, so "for a while" is offered as a
// first-class choice instead of relying on the operator to come back and lift
// it. Blank/0 = permanent, exactly as before.
async function muteAlert(id) {
  const hours = await uiPrompt({
    title: 'Mute this alert from this host',
    message: 'Silence this exact (host, event) for how many hours? '
           + 'It stops firing and any open ones are cleared; history keeps recording. '
           + 'Leave blank to mute until you lift it (Monitoring → Tuning).',
    placeholder: 'e.g. 24 — blank = until I lift it',
    confirmText: 'Mute',
  });
  if (hours === null) return;                 // cancelled
  const body = { alert_id: String(id) };
  const h = parseFloat(hours);
  if (String(hours).trim() !== '') {
    if (isNaN(h) || h < 0.25 || h > 8760) {
      toast('Enter hours between 0.25 and 8760, or leave blank for permanent', 'error', {transient: true});
      return;
    }
    body.hours = h;
  }
  const r = await api('POST', '/alert-mutes', body);
  if (r && r.ok) {
    toast('Muted — ' + (body.hours ? `for ${body.hours}h` : 'until you lift it')
      + (r.resolved ? ` · ${r.resolved} open cleared` : ''), 'success');
    // refresh whichever view surfaced the alert (dashboard widget or inbox)
    if (document.getElementById('page-home')?.classList.contains('active')) loadHome();
    else loadAlerts();
  } else toast((r && r.error) || 'Failed to mute', 'error');
}

// v5.8.0 (B1.2): open the guided remediation runner for an alert the server
// tagged with a mitigation playbook. Reuses openMitigateModal (app.js) — the
// same modal the dashboard needs-attention feed uses.
function mitigateAlert(id) {
  const a = (_alertsCache || []).find(x => x.id === id);
  if (!a) { toast('Alert not found', 'error'); return; }
  if (!a.mitigation_kind || !a.device_id) {
    toast('No remediation playbook for this alert', 'info');
    return;
  }
  openMitigateModal(a.device_id, a.mitigation_kind, a.mitigation_target || '',
                    a.device_name || a.device_id);
}

// v4.1.0 (#53): acknowledge every selected open alert in one call.
async function bulkAckAlerts() {
  const ids = Array.from(document.querySelectorAll('.alerts-row-cb:checked'))
    .map(cb => cb.dataset.id);
  if (!ids.length) return;
  const body = { ids };
  if (_alertsAckCommentEnabled) {
    const note = await uiPrompt({message: `Add a comment to ${ids.length} acknowledgement(s) (optional):`, value: ''});
    if (note === null) return;   // cancelled
    if (note.trim()) body.note = note.trim();
  }
  const r = await api('POST', '/alerts/bulk-ack', body);
  if (r && r.ok) { toast(`Acknowledged ${r.acked}`, 'success'); loadAlerts(); refreshAlertsBadge(); }
  else toast((r && r.error) || 'Failed', 'error');
}

async function resolveAlert(id) {
  if (!await uiConfirm('Mark this alert resolved?')) return;
  // v6.3.0 (UX wave 1): optimistic — the row flips to resolved instantly, the
  // POST runs after, and a server decline reverts the flip with an error toast.
  // (There is no /unresolve endpoint, so resolve keeps its confirm dialog
  // rather than moving to the undo-toast pattern the way ack did.)
  const a = (_alertsCache || []).find(x => String(x.id) === String(id));
  const prev = a ? { at: a.resolved_at, by: a.resolved_by } : null;
  if (a) {
    a.resolved_at = Math.floor(Date.now() / 1000);
    a.resolved_by = getMe() || 'me';
    renderAlerts();
  }
  const r = await api('POST', `/alerts/${encodeURIComponent(id)}/resolve`, {});
  if (r && r.ok) { toast('Alert resolved', 'success'); loadAlerts(); refreshAlertsBadge(); }
  else {
    if (a && prev) { a.resolved_at = prev.at; a.resolved_by = prev.by; renderAlerts(); }
    toast((r && r.error) || 'Failed', 'error');
  }
}

// v6.3.0 (UX wave 1): optimistic single-alert ack with a real Undo — the row
// flips instantly, the POST runs in the background, and the success toast
// carries Undo wired to POST /alerts/<id>/unack (which exists server-side for
// exactly this). A failed POST reverts the flip; a successful Undo reloads
// from the server rather than patching the (possibly refreshed) cache.
function _ackAlertOptimistic(id) {
  const a = (_alertsCache || []).find(x => String(x.id) === String(id));
  if (!a || a.acknowledged_at || a.resolved_at) return;
  const prev = { at: a.acknowledged_at, by: a.acknowledged_by };
  a.acknowledged_at = Math.floor(Date.now() / 1000);
  a.acknowledged_by = getMe() || 'me';
  renderAlerts();
  const revert = () => {
    a.acknowledged_at = prev.at; a.acknowledged_by = prev.by; renderAlerts();
  };
  let unacked = false;
  const doUnack = async () => {
    if (unacked) return;
    unacked = true;
    const u = await api('POST', `/alerts/${encodeURIComponent(id)}/unack`, {});
    if (u && u.ok) { loadAlerts(); refreshAlertsBadge(); }
    else toast((u && u.error) || 'Could not undo', 'error');
  };
  api('POST', '/alerts/bulk-ack', { ids: [String(id)] }).then(r => {
    if (r && r.ok) {
      refreshAlertsBadge();
      // v6.3.0 (1b): reachable from the toast AND the topbar undo arrow.
      uiUndoCtl.push({
        label: 'Alert acknowledged',
        alive: () => !unacked,
        undo: doUnack,
        redo: () => _ackAlertOptimistic(id),
      });
      toast('Acknowledged', 'success', { action: { label: 'Undo', icon: 'undo', fn: doUnack } });
    } else { revert(); toast((r && r.error) || 'Failed', 'error'); }
  }).catch(() => { revert(); toast('Failed', 'error'); });
}


function toggleAllAlerts(checked) {
  document.querySelectorAll('.alerts-row-cb').forEach(cb => { cb.checked = checked; });
  _updateBulkResolveBtn();
}

function updateBulkResolveBtn() { _updateBulkResolveBtn(); }
function _updateBulkResolveBtn() {
  const cbs = document.querySelectorAll('.alerts-row-cb:checked');
  const btn = document.getElementById('alerts-bulk-resolve-btn');
  if (btn) btn.classList.toggle('d-none', cbs.length === 0);
  // v4.1.0 (#53): "Ack selected" shows only when a selected row is still
  // un-acked (acking an already-acked alert is a no-op).
  const ackBtn = document.getElementById('alerts-bulk-ack-btn');
  if (ackBtn) {
    const anyUnacked = Array.from(cbs).some(cb => {
      const a = (_alertsCache || []).find(x => x.id === cb.dataset.id);
      return a && !a.acknowledged_at;
    });
    ackBtn.classList.toggle('d-none', !anyUnacked);
  }
}

async function bulkResolveAlerts() {
  const ids = Array.from(document.querySelectorAll('.alerts-row-cb:checked'))
    .map(cb => cb.dataset.id);
  if (!ids.length) return;
  if (!await uiConfirm(`Resolve ${ids.length} alert(s)?`)) return;
  const r = await api('POST', '/alerts/bulk-resolve', { ids });
  if (r && r.ok) { toast(`Resolved ${r.resolved}`, 'success'); loadAlerts(); refreshAlertsBadge(); }
  else toast((r && r.error) || 'Failed', 'error');
}

// v3.2.0 follow-up: bulk-purge resolved or all alerts
async function clearResolvedAlerts() {
  // v6.3.0 (wave 8): state the blast radius — the concrete count, not "every".
  const n = window._alertsSummary && window._alertsSummary.resolved;
  if (!await uiConfirm(`Remove every alert in "resolved" state${n ? ` (${n})` : ''}? Open and acknowledged rows stay.`)) return;
  const r = await api('DELETE', '/alerts?scope=resolved');
  if (r && r.ok) {
    toast(`Cleared ${r.removed} resolved alert(s)`, 'success');
    loadAlerts(); refreshAlertsBadge();
  } else toast((r && r.error) || 'Failed', 'error');
}

async function clearAllAlerts() {
  const s = window._alertsSummary || {};
  const n = (s.open || 0) + (s.acknowledged || 0) + (s.resolved || 0);
  if (!await uiConfirm(`Remove EVERY alert${n ? ` (${n} total: ${s.open || 0} open, ${s.acknowledged || 0} acknowledged, ${s.resolved || 0} resolved)` : ' — including open and acknowledged ones'}?\n\nThis cannot be undone. Use "Clear resolved" if you only want to purge resolved.`)) return;
  const r = await api('DELETE', '/alerts?scope=all');
  if (r && r.ok) {
    toast(`Cleared ${r.removed} alert(s)`, 'success');
    loadAlerts(); refreshAlertsBadge();
  } else toast((r && r.error) || 'Failed', 'error');
}

// ── v6.2.2: keyboard-driven inbox ────────────────────────────────────────────
// j/k move the selection, a acknowledge, r resolve, m mute, x toggle the row
// checkbox, ? shows the map, Esc clears. Active only while the Alerts page is
// visible, no modal is open, and focus isn't inside a form control — so it can
// never swallow typing in the filter box or a modal.
let _kbAlertIdx = -1;

function _kbAlertRows() {
  return [...document.querySelectorAll('#page-alerts .alerts-row[data-alert-id]')]
    .filter(r => r.offsetParent !== null);
}

function _kbAlertPaint(rows) {
  rows.forEach((r, i) => r.classList.toggle('kb-selected', i === _kbAlertIdx));
  const sel = rows[_kbAlertIdx];
  if (sel) sel.scrollIntoView({ block: 'nearest' });
}

document.addEventListener('keydown', (e) => {
  const page = document.getElementById('page-alerts');
  if (!page || !page.classList.contains('active')) return;
  if (e.ctrlKey || e.metaKey || e.altKey) return;
  if (document.body.classList.contains('modal-open')) return;
  const t = e.target;
  if (t && (t.tagName === 'INPUT' || t.tagName === 'TEXTAREA' ||
            t.tagName === 'SELECT' || t.isContentEditable)) return;
  const key = e.key;
  // NB 'Escape' deliberately FIRST: test_v3140's g-nav scanner regexes the JS
  // for arrays opening with a single lowercase letter followed by a word, and
  // an array starting with the j/k keys would false-match as a nav pair.
  if (!['Escape', 'j', 'k', 'a', 'r', 'm', 'x', '?'].includes(key)) return;
  const rows = _kbAlertRows();
  if (!rows.length) return;
  if (key === 'Escape') {
    _kbAlertIdx = -1; _kbAlertPaint(rows); return;
  }
  if (key === '?') {
    toast('Alert inbox keys — j/k: move · a: acknowledge · r: resolve · m: mute · x: select · Esc: clear', 'info');
    e.preventDefault(); return;
  }
  if (key === 'j' || key === 'k') {
    _kbAlertIdx = key === 'j'
      ? Math.min(rows.length - 1, _kbAlertIdx + 1)
      : Math.max(0, _kbAlertIdx - 1);
    _kbAlertPaint(rows);
    e.preventDefault(); return;
  }
  const row = rows[_kbAlertIdx];
  if (!row) return;
  const id = row.dataset.alertId;
  e.preventDefault();
  if (key === 'x') {
    const cb = row.querySelector('.alerts-row-cb');
    if (cb) { cb.checked = !cb.checked; _updateBulkResolveBtn(); }
  } else if (key === 'a') {
    _ackAlertOptimistic(id);   // v6.3.0: instant flip + undo toast
  } else if (key === 'r') {
    resolveAlert(id);          // keeps its own confirm dialog
  } else if (key === 'm') {
    muteAlert(id);             // keeps its own confirm/prompt flow
  }
});

// ── v6.3.1: agentic alert triage ─────────────────────────────────────────────
// POST /alerts/<id>/ai-triage runs a bounded server-side investigate loop (the
// model requests read-only evidence tools, then delivers a verdict). Result is
// stored on the alert (ai_triage) and rendered here. Reuses the generic
// ai-insight modal shell (body-level, CSP-clean).
function _renderTriageResult(el, t) {
  const v = (t && t.verdict) || {};
  const steps = (t && t.steps) || [];
  const stepsHtml = steps.map(s =>
    `<li><code>${_escapeHtml(s.tool || '?')}</code>${s.why ? ' — ' + _escapeHtml(s.why) : ''}</li>`).join('');
  el.innerHTML =
    '<div class="ai-content">' +
    `<p><strong>Root cause:</strong> ${_escapeHtml(v.root_cause || v.error || '(none given)')}` +
    (v.confidence ? ` <span class="patch-badge fs-10">${_escapeHtml(v.confidence)} confidence</span>` : '') + '</p>' +
    ((v.evidence && v.evidence.length)
      ? `<p><strong>Evidence</strong></p><ul>${v.evidence.map(e => `<li>${_escapeHtml(e)}</li>`).join('')}</ul>` : '') +
    (v.recommended_action
      ? `<p><strong>Recommended action:</strong> ${_escapeHtml(v.recommended_action)}</p>` : '') +
    (stepsHtml
      ? `<p class="hint">Evidence gathered via ${steps.length} tool call(s):</p><ul class="hint">${stepsHtml}</ul>` : '') +
    ((t && t.at) ? `<p class="hint">Run ${_formatTs(t.at)} by ${_escapeHtml(t.by || '?')}</p>` : '') +
    '</div>';
}

async function aiTriageAlert(id) {
  const titleEl = document.querySelector('#ai-insight-modal .modal-title');
  if (titleEl) titleEl.textContent = 'AI triage';
  const body = document.getElementById('ai-insight-body');
  if (body) body.innerHTML = '<div class="empty-state">Investigating — the model is gathering evidence (this runs a few AI calls)…</div>';
  openModal('ai-insight-modal');
  const r = await api('POST', `/alerts/${encodeURIComponent(id)}/ai-triage`, {}).catch(() => null);
  if (!r || !r.ok) {
    if (body) body.innerHTML = `<div class="empty-state">${_escapeHtml((r && r.error) || 'Triage failed — is the AI assistant configured?')}</div>`;
    return;
  }
  if (body) _renderTriageResult(body, r.ai_triage);
  loadAlerts();   // pick up the stored "AI verdict" badge
}

function showAlertTriage(id) {
  const a = (_alertsCache || []).find(x => String(x.id) === String(id));
  if (!a || !a.ai_triage) { toast('No stored triage for this alert', 'info'); return; }
  const titleEl = document.querySelector('#ai-insight-modal .modal-title');
  if (titleEl) titleEl.textContent = 'AI triage';
  const body = document.getElementById('ai-insight-body');
  if (body) _renderTriageResult(body, a.ai_triage);
  openModal('ai-insight-modal');
}
